import React, { useEffect, useState } from 'react';
import { useAuth } from '../context/AuthContext';
import { leavesAPI, leaveBalanceAPI } from '../services/api';
import {
  PageHeader, Card, Table, Btn, Modal, Input, Select, Textarea, Badge, Tabs, toast,
} from '../components/ui';
import { Plus, X, Check, Edit2 } from 'lucide-react';

const STATUS_BADGE = {
  pending:         { variant: 'warning', label: 'Pending' },
  approved_by_hod: { variant: 'info',    label: 'HOD Approved' },
  approved:        { variant: 'success', label: 'Approved' },
  rejected:        { variant: 'danger',  label: 'Rejected' },
  cancelled:       { variant: 'neutral', label: 'Cancelled' },
};

export default function Leaves() {
  const { hasRole } = useAuth();
  const [tab, setTab] = useState('my');
  const [myLeaves, setMyLeaves] = useState([]);
  const [allLeaves, setAllLeaves] = useState([]);
  const [balances, setBalances] = useState([]);
  const [loading, setLoading] = useState(true);
  const [applying, setApplying] = useState(false);
  const [editLeave, setEditLeave] = useState(null);
  const [editing, setEditing] = useState(false);
  const [form, setForm] = useState({
    leave_type: 'casual', start_date: '', end_date: '', reason: '',
  });

  const isAdmin = hasRole('admin');
  const isHR = hasRole('hr');
  const isHOD = hasRole('department_head');
  const canManage = isAdmin || isHR || isHOD;

  const tabs = [
    { key: 'my', label: 'My Leaves' },
    ...(canManage ? [{ key: 'manage', label: 'All Employees' }] : []),
  ];

  const loadData = async () => {
    setLoading(true);
    try {
      const [myRes, balRes] = await Promise.all([
        leavesAPI.myLeaves(),
        leaveBalanceAPI.myBalance().catch(() => ({ data: [] })),
      ]);
      setMyLeaves(myRes.data);
      setBalances(balRes.data || []);

      if (canManage) {
        try {
          let data;
          if (isAdmin) {
            const res = await leavesAPI.adminQueue();
            data = res.data;
          } else if (isHR) {
            const res = await leavesAPI.hrAll();
            data = res.data;
          } else if (isHOD) {
            const res = await leavesAPI.hodPending();
            data = res.data;
          }
          setAllLeaves(data || []);
        } catch {
          setAllLeaves([]);
        }
      }
    } catch (e) {
      toast(e.response?.data?.detail || 'Failed to load leaves', 'error');
    } finally {
      setLoading(false);
    }
  };

  // eslint-disable-next-line react-hooks/exhaustive-deps
  useEffect(() => { loadData(); }, []);

  const handleApply = async (e) => {
    e.preventDefault();
    setApplying(true);
    try {
      await leavesAPI.apply(form);
      toast('Leave applied successfully', 'success');
      setShowApply(false);
      setForm({ leave_type: 'casual', start_date: '', end_date: '', reason: '' });
      loadData();
    } catch (e) {
      toast(e.response?.data?.detail || 'Failed to apply leave', 'error');
    } finally {
      setApplying(false);
    }
  };

  const handleCancel = async (id) => {
    try {
      await leavesAPI.cancel(id);
      toast('Leave cancelled', 'success');
      loadData();
    } catch (e) {
      toast(e.response?.data?.detail || 'Failed to cancel leave', 'error');
    }
  };

  const handleAction = async (leaveId, action) => {
    try {
      if (isAdmin) {
        await leavesAPI.adminProcess(leaveId, action);
      } else if (isHR) {
        await leavesAPI.hrProcess(leaveId, action);
      } else if (isHOD) {
        if (action === 'approve') await leavesAPI.hodApprove(leaveId);
        else await leavesAPI.hodReject(leaveId);
      }
      toast(`Leave ${action}d successfully`, 'success');
      loadData();
    } catch (e) {
      toast(e.response?.data?.detail || `Failed to ${action} leave`, 'error');
    }
  };

  const handleEditSubmit = async (e) => {
    e.preventDefault();
    setEditing(true);
    try {
      await leavesAPI.hrUpdate(editLeave.id, {
        start_date: editLeave.start_date,
        end_date: editLeave.end_date,
        reason: editLeave.reason,
      });
      toast('Leave record updated successfully', 'success');
      setEditLeave(null);
      loadData();
    } catch (e) {
      toast(e.response?.data?.detail || 'Failed to update leave', 'error');
    } finally {
      setEditing(false);
    }
  };

  const myCols = [
    { key: 'leave_type', label: 'Type', render: (r) => (
      <span style={{ textTransform: 'capitalize', fontWeight: 500 }}>{r.leave_type}</span>
    )},
    { key: 'start_date', label: 'Start Date' },
    { key: 'end_date', label: 'End Date' },
    { key: 'reason', label: 'Reason', render: (r) => (
      <span style={{ maxWidth: 200, display: 'inline-block' }} className="truncate">{r.reason}</span>
    )},
    { key: 'status', label: 'Status', render: (r) => {
      const s = STATUS_BADGE[r.status] || STATUS_BADGE.pending;
      return <Badge variant={s.variant}>{s.label}</Badge>;
    }},
    { key: 'actions', label: '', render: (r) =>
      r.status === 'pending' ? (
        <Btn variant="ghost" size="xs" onClick={() => handleCancel(r.id)} style={{ color: 'var(--danger)' }}>
          <X size={14} /> Cancel
        </Btn>
      ) : null
    },
  ];

  const manageCols = [
    { key: 'employee_id', label: 'Emp ID' },
    { key: 'leave_type', label: 'Type', render: (r) => (
      <span style={{ textTransform: 'capitalize', fontWeight: 500 }}>{r.leave_type}</span>
    )},
    { key: 'start_date', label: 'Start' },
    { key: 'end_date', label: 'End' },
    { key: 'reason', label: 'Reason', render: (r) => (
      <span style={{ maxWidth: 180, display: 'inline-block' }} className="truncate">{r.reason}</span>
    )},
    { key: 'status', label: 'Status', render: (r) => {
      const s = STATUS_BADGE[r.status] || STATUS_BADGE.pending;
      return <Badge variant={s.variant}>{s.label}</Badge>;
    }},
    { key: 'actions', label: 'Actions', render: (r) => {
      const canApprove =
        (isHOD && r.status === 'pending') ||
        (isHR && r.status === 'approved_by_hod') ||
        (isAdmin && r.status === 'pending');

      if (!canApprove && !isHR) return null;
      return (
        <div style={{ display: 'flex', gap: 6 }}>
          {canApprove && (
            <>
              <Btn variant="success" size="xs" onClick={() => handleAction(r.id, 'approve')}>
                <Check size={13} /> Approve
              </Btn>
              <Btn variant="danger" size="xs" onClick={() => handleAction(r.id, 'reject')}>
                <X size={13} /> Reject
              </Btn>
            </>
          )}
          {isHR && (
            <Btn variant="secondary" size="xs" onClick={() => setEditLeave(r)}>
              <Edit2 size={13} /> Edit
            </Btn>
          )}
        </div>
      );
    }},
  ];

  return (
    <>
      <PageHeader
        title="Leave Management"
        subtitle="Apply for leave and manage leave requests"
        actions={
          <Btn onClick={() => setShowApply(true)}>
            <Plus size={16} /> Apply Leave
          </Btn>
        }
      />

      {/* Leave Balance Cards */}
      {balances.length > 0 && (
        <div className="grid-stats" style={{ marginBottom: 24 }}>
          {balances.map((b) => (
            <Card key={b.leave_type} style={{ padding: 18 }}>
              <div style={{ textTransform: 'capitalize', fontWeight: 600, fontSize: 14, marginBottom: 8, color: 'var(--text-dark)' }}>
                {b.leave_type} Leave
              </div>
              <div style={{ display: 'flex', alignItems: 'baseline', gap: 6 }}>
                <span style={{ fontSize: 28, fontWeight: 700, color: 'var(--primary)' }}>
                  {b.remaining_days}
                </span>
                <span style={{ fontSize: 13, color: 'var(--gray-500)' }}>
                  / {b.total_days} days remaining
                </span>
              </div>
              <div
                style={{
                  height: 4,
                  background: 'var(--gray-200)',
                  borderRadius: 2,
                  marginTop: 10,
                  overflow: 'hidden',
                }}
              >
                <div
                  style={{
                    height: '100%',
                    width: `${b.total_days > 0 ? ((b.remaining_days / b.total_days) * 100) : 0}%`,
                    background: 'var(--primary)',
                    borderRadius: 2,
                    transition: 'width 0.3s ease',
                  }}
                />
              </div>
            </Card>
          ))}
        </div>
      )}

      <Card style={{ padding: 0, overflow: 'hidden' }}>
        <div style={{ padding: '16px 20px 0' }}>
          <Tabs tabs={tabs} active={tab} onChange={setTab} />
        </div>

        {tab === 'my' && <Table cols={myCols} rows={myLeaves} loading={loading} emptyMsg="No leave records found" />}
        {tab === 'manage' && <Table cols={manageCols} rows={allLeaves} loading={loading} emptyMsg="No leave requests to manage" />}
      </Card>

      {/* Apply Leave Modal */}
      <Modal open={showApply} onClose={() => setShowApply(false)} title="Apply for Leave">
        <form onSubmit={handleApply}>
          <Select
            label="Leave Type"
            value={form.leave_type}
            onChange={(e) => setForm({ ...form, leave_type: e.target.value })}
            id="leave-type"
          >
            <option value="casual">Casual</option>
            <option value="sick">Sick</option>
            <option value="earned">Earned</option>
            <option value="unpaid">Unpaid</option>
          </Select>
          <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '0 16px' }}>
            <Input
              label="Start Date"
              type="date"
              value={form.start_date}
              onChange={(e) => setForm({ ...form, start_date: e.target.value })}
              required
              id="leave-start"
            />
            <Input
              label="End Date"
              type="date"
              value={form.end_date}
              onChange={(e) => setForm({ ...form, end_date: e.target.value })}
              required
              id="leave-end"
            />
          </div>
          <Textarea
            label="Reason"
            value={form.reason}
            onChange={(e) => setForm({ ...form, reason: e.target.value })}
            placeholder="Provide a reason for your leave"
            required
            id="leave-reason"
          />
          <div style={{ display: 'flex', justifyContent: 'flex-end', gap: 10, marginTop: 8 }}>
            <Btn variant="secondary" onClick={() => setShowApply(false)}>Cancel</Btn>
            <Btn type="submit" loading={applying}>Submit Leave</Btn>
          </div>
        </form>
      </Modal>

      {/* HR Edit Leave Modal */}
      {isHR && editLeave && (
        <Modal open={!!editLeave} onClose={() => setEditLeave(null)} title="Edit Leave Record (HR Only)">
          <form onSubmit={handleEditSubmit}>
            <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '0 16px' }}>
              <Input
                label="Start Date"
                type="date"
                value={editLeave.start_date.split('T')[0]} // Ensure format
                onChange={(e) => setEditLeave({ ...editLeave, start_date: e.target.value })}
                required
                id="edit-leave-start"
              />
              <Input
                label="End Date"
                type="date"
                value={editLeave.end_date.split('T')[0]}
                onChange={(e) => setEditLeave({ ...editLeave, end_date: e.target.value })}
                required
                id="edit-leave-end"
              />
            </div>
            <Textarea
              label="Reason"
              value={editLeave.reason}
              onChange={(e) => setEditLeave({ ...editLeave, reason: e.target.value })}
              required
              id="edit-leave-reason"
            />
            <div style={{ display: 'flex', justifyContent: 'flex-end', gap: 10, marginTop: 8 }}>
              <Btn variant="secondary" onClick={() => setEditLeave(null)}>Cancel</Btn>
              <Btn type="submit" loading={editing}>Update Record</Btn>
            </div>
          </form>
        </Modal>
      )}
    </>
  );
}
